use crate::types::{DecideInput, DecideOutput};
use std::f64::consts::PI;

/// Compares two real numbers with six-significant-digit precision.
/// Returns "LT" if a < b, "EQ" if a == b, or "GT" if a > b.
fn realcompare(a: f64, b: f64) -> &'static str {
    let epsilon = 1e-6 * (a.abs().max(b.abs())).max(1.0);
    let diff = a - b;

    if diff.abs() <= epsilon {
        "EQ"
    } else if diff < 0.0 {
        "LT"
    } else {
        "GT"
    }
}

/// Compute Euclidean distance between two points
fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    (dx * dx + dy * dy).sqrt()
}

/// Compute the angle at vertex (middle point) formed by three points.
/// Returns the angle in radians, or None if the vertex coincides with either endpoint.
fn compute_angle(p1: (f64, f64), vertex: (f64, f64), p3: (f64, f64)) -> Option<f64> {
    // Vector from vertex to p1
    let v1 = (p1.0 - vertex.0, p1.1 - vertex.1);
    // Vector from vertex to p3
    let v3 = (p3.0 - vertex.0, p3.1 - vertex.1);

    // Check if vertex coincides with either endpoint
    if (v1.0 == 0.0 && v1.1 == 0.0) || (v3.0 == 0.0 && v3.1 == 0.0) {
        return None;
    }

    let dot = v1.0 * v3.0 + v1.1 * v3.1;
    let len1 = (v1.0 * v1.0 + v1.1 * v1.1).sqrt();
    let len3 = (v3.0 * v3.0 + v3.1 * v3.1).sqrt();

    if len1 == 0.0 || len3 == 0.0 {
        return None;
    }

    let cos_angle = dot / (len1 * len3);
    // Clamp to [-1, 1] to handle floating point errors
    let cos_angle = cos_angle.max(-1.0).min(1.0);
    Some(cos_angle.acos())
}

/// Compute the area of a triangle formed by three points using the shoelace formula
fn triangle_area(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> f64 {
    ((p1.0 * (p2.1 - p3.1) + p2.0 * (p3.1 - p1.1) + p3.0 * (p1.1 - p2.1)).abs()) / 2.0
}

/// Find the smallest circle containing three points (or determine if no finite circle exists)
fn smallest_circle_three_points(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> Option<(f64, f64, f64)> {
    // Try the circumcircle
    let ax = p1.0;
    let ay = p1.1;
    let bx = p2.0;
    let by = p2.1;
    let cx = p3.0;
    let cy = p3.1;

    let d = 2.0 * (ax * (by - cy) + bx * (cy - ay) + cx * (ay - by));

    if d.abs() < 1e-10 {
        // Points are collinear; return circle with two farthest points as diameter
        let d12 = distance(ax, ay, bx, by);
        let d23 = distance(bx, by, cx, cy);
        let d13 = distance(ax, ay, cx, cy);

        if d12 >= d23 && d12 >= d13 {
            let cx = (ax + bx) / 2.0;
            let cy = (ay + by) / 2.0;
            let r = d12 / 2.0;
            return Some((cx, cy, r));
        } else if d23 >= d12 && d23 >= d13 {
            let cx = (bx + cx) / 2.0;
            let cy = (by + cy) / 2.0;
            let r = d23 / 2.0;
            return Some((cx, cy, r));
        } else {
            let cx = (ax + cx) / 2.0;
            let cy = (ay + cy) / 2.0;
            let r = d13 / 2.0;
            return Some((cx, cy, r));
        }
    }

    let ux = ((ax * ax + ay * ay) * (by - cy) + (bx * bx + by * by) * (cy - ay) + (cx * cx + cy * cy) * (ay - by)) / d;
    let uy = ((ax * ax + ay * ay) * (cx - bx) + (bx * bx + by * by) * (ax - cx) + (cx * cx + cy * cy) * (bx - ax)) / d;

    let r = distance(ux, uy, ax, ay);
    Some((ux, uy, r))
}

/// Check if three points can be contained within or on a circle of given radius
fn fits_in_circle(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64), radius: f64) -> bool {
    if let Some((_cx, _cy, r)) = smallest_circle_three_points(p1, p2, p3) {
        realcompare(r, radius) != "GT"
    } else {
        true
    }
}

/// Compute the distance from a point to a line defined by two points
fn point_to_line_distance(point: (f64, f64), line_p1: (f64, f64), line_p2: (f64, f64)) -> f64 {
    let px = point.0;
    let py = point.1;
    let x1 = line_p1.0;
    let y1 = line_p1.1;
    let x2 = line_p2.0;
    let y2 = line_p2.1;

    let dx = x2 - x1;
    let dy = y2 - y1;
    let num = (dy * px - dx * py + x2 * y1 - y2 * x1).abs();
    let denom = (dx * dx + dy * dy).sqrt();

    if denom == 0.0 {
        distance(px, py, x1, y1)
    } else {
        num / denom
    }
}

/// Determine the quadrant for a point (following priority rules: I, II, III, IV)
fn get_quadrant(x: f64, y: f64) -> i32 {
    if x > 0.0 {
        if y >= 0.0 { 1 } else { 4 }
    } else if x < 0.0 {
        if y > 0.0 { 2 } else { 3 }
    } else {
        // x == 0
        if y > 0.0 { 2 } else { 1 }
    }
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let n = input.numpoints;
    let mut cmv = vec![false; 15];

    // LIC 0 (index 0): There exists at least one set of two consecutive data points
    // that are a distance greater than LENGTH1 apart.
    {
        for i in 0..n - 1 {
            let d = distance(input.x[i], input.y[i], input.x[i + 1], input.y[i + 1]);
            if realcompare(d, input.parameters.length1) == "GT" {
                cmv[0] = true;
                break;
            }
        }
    }

    // LIC 1 (index 1): There exists at least one set of three consecutive data points
    // that cannot all be contained within or on a circle of radius RADIUS1.
    {
        for i in 0..n - 2 {
            let p1 = (input.x[i], input.y[i]);
            let p2 = (input.x[i + 1], input.y[i + 1]);
            let p3 = (input.x[i + 2], input.y[i + 2]);
            if !fits_in_circle(p1, p2, p3, input.parameters.radius1) {
                cmv[1] = true;
                break;
            }
        }
    }

    // LIC 2 (index 2): There exists at least one set of three consecutive data points
    // which form an angle such that: angle < (PI - EPSILON) or angle > (PI + EPSILON)
    {
        for i in 0..n - 2 {
            let p1 = (input.x[i], input.y[i]);
            let p2 = (input.x[i + 1], input.y[i + 1]);
            let p3 = (input.x[i + 2], input.y[i + 2]);
            if let Some(angle) = compute_angle(p1, p2, p3) {
                let lower = PI - input.parameters.epsilon;
                let upper = PI + input.parameters.epsilon;
                if realcompare(angle, lower) == "LT" || realcompare(angle, upper) == "GT" {
                    cmv[2] = true;
                    break;
                }
            }
        }
    }

    // LIC 3 (index 3): There exists at least one set of three consecutive data points
    // that are the vertices of a triangle with area greater than AREA1.
    {
        for i in 0..n - 2 {
            let p1 = (input.x[i], input.y[i]);
            let p2 = (input.x[i + 1], input.y[i + 1]);
            let p3 = (input.x[i + 2], input.y[i + 2]);
            let area = triangle_area(p1, p2, p3);
            if realcompare(area, input.parameters.area1) == "GT" {
                cmv[3] = true;
                break;
            }
        }
    }

    // LIC 4 (index 4): There exists at least one set of Q_PTS consecutive data points
    // that lie in more than QUADS quadrants.
    {
        let q = input.parameters.q_pts;
        'outer: for i in 0..n - q + 1 {
            let mut quadrants = vec![false; 4];
            for j in i..i + q {
                let quad = get_quadrant(input.x[j], input.y[j]);
                quadrants[(quad - 1) as usize] = true;
            }
            let count = quadrants.iter().filter(|&&x| x).count();
            if count as usize > input.parameters.quads {
                cmv[4] = true;
                break 'outer;
            }
        }
    }

    // LIC 5 (index 5): There exists at least one set of two consecutive data points,
    // (X[i], Y[i]) and (X[j], Y[j]), such that X[j] - X[i] < 0 (where i = j - 1).
    {
        for i in 0..n - 1 {
            if input.x[i + 1] - input.x[i] < 0.0 {
                cmv[5] = true;
                break;
            }
        }
    }

    // LIC 6 (index 6): There exists at least one set of N_PTS consecutive data points
    // such that at least one of the points lies a distance greater than DIST from the
    // line joining the first and last of these N_PTS points.
    {
        if n >= 3 {
            let epts = input.parameters.n_pts;
            'outer: for i in 0..n - epts + 1 {
                let p_first = (input.x[i], input.y[i]);
                let p_last = (input.x[i + epts - 1], input.y[i + epts - 1]);
                for j in i + 1..i + epts - 1 {
                    let p = (input.x[j], input.y[j]);
                    let dist = point_to_line_distance(p, p_first, p_last);
                    if realcompare(dist, input.parameters.dist) == "GT" {
                        cmv[6] = true;
                        break 'outer;
                    }
                }
            }
        }
    }

    // LIC 7 (index 7): There exists at least one set of two data points separated by
    // exactly K_PTS consecutive intervening points that are a distance greater than
    // LENGTH1 apart. Condition not met when NUMPOINTS < 3.
    {
        if n >= 3 {
            let k = input.parameters.k_pts;
            for i in 0..n - k - 1 {
                let d = distance(input.x[i], input.y[i], input.x[i + k + 1], input.y[i + k + 1]);
                if realcompare(d, input.parameters.length1) == "GT" {
                    cmv[7] = true;
                    break;
                }
            }
        }
    }

    // LIC 8 (index 8): There exists at least one set of three data points separated by
    // exactly A_PTS and B_PTS consecutive intervening points, respectively, that cannot
    // be contained within or on a circle of radius RADIUS1. Condition not met when NUMPOINTS < 5.
    {
        if n >= 5 {
            let a = input.parameters.a_pts;
            let b = input.parameters.b_pts;
            'outer: for i in 0..n - a - b - 2 {
                let p1 = (input.x[i], input.y[i]);
                let p2 = (input.x[i + a + 1], input.y[i + a + 1]);
                let p3 = (input.x[i + a + b + 2], input.y[i + a + b + 2]);
                if !fits_in_circle(p1, p2, p3, input.parameters.radius1) {
                    cmv[8] = true;
                    break 'outer;
                }
            }
        }
    }

    // LIC 9 (index 9): There exists at least one set of three data points separated by
    // exactly C_PTS and D_PTS consecutive intervening points, respectively, that form
    // an angle such that angle < (PI - EPSILON) or angle > (PI + EPSILON).
    // Condition not met when NUMPOINTS < 5.
    {
        if n >= 5 {
            let c = input.parameters.c_pts;
            let d = input.parameters.d_pts;
            'outer: for i in 0..n - c - d - 2 {
                let p1 = (input.x[i], input.y[i]);
                let p2 = (input.x[i + c + 1], input.y[i + c + 1]);
                let p3 = (input.x[i + c + d + 2], input.y[i + c + d + 2]);
                if let Some(angle) = compute_angle(p1, p2, p3) {
                    let lower = PI - input.parameters.epsilon;
                    let upper = PI + input.parameters.epsilon;
                    if realcompare(angle, lower) == "LT" || realcompare(angle, upper) == "GT" {
                        cmv[9] = true;
                        break 'outer;
                    }
                }
            }
        }
    }

    // LIC 10 (index 10): There exists at least one set of three data points separated
    // by exactly E_PTS and F_PTS consecutive intervening points, respectively, that
    // are the vertices of a triangle with area greater than AREA1.
    // Condition not met when NUMPOINTS < 5.
    {
        if n >= 5 {
            let e = input.parameters.e_pts;
            let f = input.parameters.f_pts;
            'outer: for i in 0..n - e - f - 2 {
                let p1 = (input.x[i], input.y[i]);
                let p2 = (input.x[i + e + 1], input.y[i + e + 1]);
                let p3 = (input.x[i + e + f + 2], input.y[i + e + f + 2]);
                let area = triangle_area(p1, p2, p3);
                if realcompare(area, input.parameters.area1) == "GT" {
                    cmv[10] = true;
                    break 'outer;
                }
            }
        }
    }

    // LIC 11 (index 11): There exists at least one set of two data points,
    // (X[i], Y[i]) and (X[j], Y[j]), separated by exactly G_PTS consecutive
    // intervening points, such that X[j] - X[i] < 0 (where i < j).
    // Condition not met when NUMPOINTS < 3.
    {
        if n >= 3 {
            let g = input.parameters.g_pts;
            for i in 0..n - g - 1 {
                if input.x[i + g + 1] - input.x[i] < 0.0 {
                    cmv[11] = true;
                    break;
                }
            }
        }
    }

    // LIC 12 (index 12): There exists at least one set of two data points separated
    // by exactly K_PTS consecutive intervening points, which are a distance greater
    // than LENGTH1 apart. In addition, there exists at least one set of two data points
    // separated by exactly K_PTS consecutive intervening points, that are a distance
    // less than LENGTH2 apart. Both parts must be true.
    // Condition not met when NUMPOINTS < 3.
    {
        if n >= 3 {
            let k = input.parameters.k_pts;
            let mut found_greater = false;
            let mut found_less = false;
            for i in 0..n - k - 1 {
                let d = distance(input.x[i], input.y[i], input.x[i + k + 1], input.y[i + k + 1]);
                if realcompare(d, input.parameters.length1) == "GT" {
                    found_greater = true;
                }
                if realcompare(d, input.parameters.length2) == "LT" {
                    found_less = true;
                }
            }
            cmv[12] = found_greater && found_less;
        }
    }

    // LIC 13 (index 13): There exists at least one set of three data points separated
    // by exactly A_PTS and B_PTS consecutive intervening points, respectively, that
    // cannot be contained within or on a circle of radius RADIUS1. In addition, there
    // exists at least one set of three data points separated by exactly A_PTS and B_PTS
    // consecutive intervening points, respectively, that can be contained in or on a
    // circle of radius RADIUS2. Both parts must be true.
    // Condition not met when NUMPOINTS < 5.
    {
        if n >= 5 {
            let a = input.parameters.a_pts;
            let b = input.parameters.b_pts;
            let mut found_not_in = false;
            let mut found_in = false;
            for i in 0..n - a - b - 2 {
                let p1 = (input.x[i], input.y[i]);
                let p2 = (input.x[i + a + 1], input.y[i + a + 1]);
                let p3 = (input.x[i + a + b + 2], input.y[i + a + b + 2]);
                if !fits_in_circle(p1, p2, p3, input.parameters.radius1) {
                    found_not_in = true;
                }
                if fits_in_circle(p1, p2, p3, input.parameters.radius2) {
                    found_in = true;
                }
            }
            cmv[13] = found_not_in && found_in;
        }
    }

    // LIC 14 (index 14): There exists at least one set of three data points separated
    // by exactly E_PTS and F_PTS consecutive intervening points, respectively, that are
    // the vertices of a triangle with area greater than AREA1. In addition, there exist
    // three data points separated by exactly E_PTS and F_PTS consecutive intervening
    // points, respectively, that are the vertices of a triangle with area less than AREA2.
    // Both parts must be true. Condition not met when NUMPOINTS < 5.
    {
        if n >= 5 {
            let e = input.parameters.e_pts;
            let f = input.parameters.f_pts;
            let mut found_greater = false;
            let mut found_less = false;
            for i in 0..n - e - f - 2 {
                let p1 = (input.x[i], input.y[i]);
                let p2 = (input.x[i + e + 1], input.y[i + e + 1]);
                let p3 = (input.x[i + e + f + 2], input.y[i + e + f + 2]);
                let area = triangle_area(p1, p2, p3);
                if realcompare(area, input.parameters.area1) == "GT" {
                    found_greater = true;
                }
                if realcompare(area, input.parameters.area2) == "LT" {
                    found_less = true;
                }
            }
            cmv[14] = found_greater && found_less;
        }
    }

    // Build PUM (Preliminary Unlocking Matrix)
    let mut pum = vec![vec![false; 15]; 15];

    // Set diagonal elements from input
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
    }

    // Set off-diagonal elements based on LCM and CMV
    for i in 0..15 {
        for j in 0..15 {
            if i != j {
                let connector = &input.lcm[i][j];
                pum[i][j] = match connector.as_str() {
                    "NOTUSED" => true,
                    "ANDD" => cmv[i] && cmv[j],
                    "ORR" => cmv[i] || cmv[j],
                    _ => false,
                };
            }
        }
    }

    // Build FUV (Final Unlocking Vector)
    let mut fuv = vec![false; 15];
    for i in 0..15 {
        // FUV[i] is true if PUM[i,i] is false OR all elements in PUM row i are true
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            fuv[i] = pum[i].iter().all(|&x| x);
        }
    }

    // Determine LAUNCH decision
    let launch = fuv.iter().all(|&x| x);

    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
